  // ═══ 党史知识 (48) ═══
  PoliticalTerm(category: 'dszs', title: '伟大建党精神', definition: '坚持真理、坚守理想，践行初心、担当使命，不怕牺牲、英勇斗争，对党忠诚、不负人民。这是中国共产党的精神之源。'),
  PoliticalTerm(category: 'dszs', title: '井冈山精神', definition: '坚定信念、艰苦奋斗，实事求是、敢闯新路，依靠群众、勇于胜利。'),
  PoliticalTerm(category: 'dszs', title: '苏区精神', definition: '坚定信念、求真务实、一心为民、清正廉洁、艰苦奋斗、争创一流、无私奉献。'),
  PoliticalTerm(category: 'dszs', title: '长征精神', definition: '把全国人民和中华民族的根本利益看得高于一切，坚定革命的理想和信念，坚信正义事业必然胜利的精神；为了救国救民，不怕任何艰难险阻，不惜付出一切牺牲的精神；坚持独立自主、实事求是，一切从实际出发的精神；顾全大局、严守纪律、紧密团结的精神；紧紧依靠人民群众，同人民群众生死相依、患难与共、艰苦奋斗的精神。'),
  PoliticalTerm(category: 'dszs', title: '遵义会议精神', definition: '坚定信念、实事求是、独立自主、敢闯新路、民主团结。'),
  PoliticalTerm(category: 'dszs', title: '延安精神', definition: '坚定正确的政治方向，解放思想、实事求是的思想路线，全心全意为人民服务的根本宗旨，自力更生、艰苦奋斗的创业精神。'),
  PoliticalTerm(category: 'dszs', title: '抗战精神', definition: '天下兴亡、匹夫有责的爱国情怀，视死如归、宁死不屈的民族气节，不畏强暴、血战到底的英雄气概，百折不挠、坚忍不拔的必胜信念。'),
  PoliticalTerm(category: 'dszs', title: '红岩精神', definition: '坚如磐石的理想信念、和衷共济的爱国情怀、不折不挠的凛然斗志、坚贞不屈的浩然正气。'),
  PoliticalTerm(category: 'dszs', title: '西柏坡精神', definition: '谦虚谨慎、艰苦奋斗、实事求是、一心为民。核心是"两个务必"：务必使同志们继续地保持谦虚谨慎不骄不躁的作风，务必使同志们继续地保持艰苦奋斗的作风。'),
  PoliticalTerm(category: 'dszs', title: '照金精神', definition: '不怕牺牲、顽强拼搏的英雄气概，独立自主、开拓进取的创新勇气，从实际出发、密切联系群众的工作作风。'),
  PoliticalTerm(category: 'dszs', title: '东北抗联精神', definition: '坚定的信仰信念、高尚的爱国情操、伟大的牺牲精神。'),
  PoliticalTerm(category: 'dszs', title: '南泥湾精神', definition: '自力更生、艰苦奋斗的革命精神，调查研究、实事求是的工作方法，上下一致、共克时艰的优良作风。'),
  PoliticalTerm(category: 'dszs', title: '太行精神（吕梁精神）', definition: '不怕牺牲、不畏艰险，百折不挠、艰苦奋斗，万众一心、敢于胜利，英勇奋斗、无私奉献。'),
  PoliticalTerm(category: 'dszs', title: '大别山精神', definition: '坚守信念、胸怀全局、团结奋进、勇当前锋。'),
  PoliticalTerm(category: 'dszs', title: '沂蒙精神', definition: '党群同心、军民情深、水乳交融、生死与共。'),
  PoliticalTerm(category: 'dszs', title: '老区精神', definition: '爱党信党、坚定不移的理想信念；舍生忘死、无私奉献的博大胸怀；不屈不挠、敢于胜利的英雄气概；自强不息、艰苦奋斗的顽强斗志；求真务实、开拓创新的科学态度；鱼水情深、生死相依的光荣传统。'),
  PoliticalTerm(category: 'dszs', title: '张思德精神', definition: '全心全意为人民服务。'),
  PoliticalTerm(category: 'dszs', title: '抗美援朝精神', definition: '祖国和人民利益高于一切、为了祖国和民族的尊严而奋不顾身的爱国主义精神，英勇顽强、舍生忘死的革命英雄主义精神，不畏艰难困苦、始终保持高昂士气的革命乐观主义精神，为完成祖国和人民赋予的使命、慷慨奉献自己一切的革命忠诚精神，为了人类和平与正义事业而奋斗的国际主义精神。'),
  PoliticalTerm(category: 'dszs', title: '"两弹一星"精神', definition: '热爱祖国、无私奉献，自力更生、艰苦奋斗，大力协同、勇于登攀。'),
  PoliticalTerm(category: 'dszs', title: '雷锋精神', definition: '热爱党、热爱祖国、热爱社会主义的崇高理想和坚定信念；服务人民、助人为乐的奉献精神；干一行爱一行、专一行精一行的敬业精神；锐意进取、自强不息的创新精神；艰苦奋斗、勤俭节约的创业精神。'),
  PoliticalTerm(category: 'dszs', title: '焦裕禄精神', definition: '亲民爱民、艰苦奋斗、科学求实、迎难而上、无私奉献。'),
  PoliticalTerm(category: 'dszs', title: '大庆精神（铁人精神）', definition: '爱国、创业、求实、奉献。'),
  PoliticalTerm(category: 'dszs', title: '红旗渠精神', definition: '自力更生、艰苦创业、团结协作、无私奉献。'),
  PoliticalTerm(category: 'dszs', title: '北大荒精神', definition: '艰苦奋斗、勇于开拓、顾全大局、无私奉献。'),
  PoliticalTerm(category: 'dszs', title: '塞罕坝精神', definition: '牢记使命、艰苦创业、绿色发展。'),
  PoliticalTerm(category: 'dszs', title: '"两路"精神', definition: '一不怕苦、二不怕死，顽强拼搏、甘当路石，军民一家、民族团结。'),
  PoliticalTerm(category: 'dszs', title: '老西藏精神（孔繁森精神）', definition: '特别能吃苦、特别能战斗、特别能忍耐、特别能团结、特别能奉献。'),
  PoliticalTerm(category: 'dszs', title: '西迁精神', definition: '胸怀大局、无私奉献、弘扬传统、艰苦创业。'),
  PoliticalTerm(category: 'dszs', title: '王杰精神', definition: '一不怕苦、二不怕死。'),
  PoliticalTerm(category: 'dszs', title: '改革开放精神', definition: '解放思想、实事求是，敢闯敢试、勇于创新，互利合作、命运与共。'),
  PoliticalTerm(category: 'dszs', title: '特区精神', definition: '敢闯敢试、敢为人先、埋头苦干。'),
  PoliticalTerm(category: 'dszs', title: '抗洪精神', definition: '万众一心、众志成城，不怕困难、顽强拼搏，坚韧不拔、敢于胜利。'),
  PoliticalTerm(category: 'dszs', title: '抗击非典精神', definition: '万众一心、众志成城，团结互助、和衷共济，迎难而上、敢于胜利。'),
  PoliticalTerm(category: 'dszs', title: '抗震救灾精神', definition: '万众一心、众志成城，不畏艰险、百折不挠，以人为本、尊重科学。'),
  PoliticalTerm(category: 'dszs', title: '载人航天精神', definition: '特别能吃苦、特别能战斗、特别能攻关、特别能奉献。'),
  PoliticalTerm(category: 'dszs', title: '劳模精神', definition: '爱岗敬业、争创一流，艰苦奋斗、勇于创新，淡泊名利、甘于奉献。'),
  PoliticalTerm(category: 'dszs', title: '劳动精神', definition: '崇尚劳动、热爱劳动、辛勤劳动、诚实劳动。'),
  PoliticalTerm(category: 'dszs', title: '工匠精神', definition: '执着专注、精益求精、一丝不苟、追求卓越。'),
  PoliticalTerm(category: 'dszs', title: '青藏铁路精神', definition: '挑战极限、勇创一流。'),
  PoliticalTerm(category: 'dszs', title: '女排精神', definition: '祖国至上、团结协作、顽强拼搏、永不言败。'),
  PoliticalTerm(category: 'dszs', title: '脱贫攻坚精神', definition: '上下同心、尽锐出战、精准务实、开拓创新、攻坚克难、不负人民。'),
  PoliticalTerm(category: 'dszs', title: '抗疫精神', definition: '生命至上、举国同心、舍生忘死、尊重科学、命运与共。'),
  PoliticalTerm(category: 'dszs', title: '"三牛"精神', definition: '为民服务孺子牛、创新发展拓荒牛、艰苦奋斗老黄牛。'),
  PoliticalTerm(category: 'dszs', title: '科学家精神', definition: '胸怀祖国、服务人民的爱国精神，勇攀高峰、敢为人先的创新精神，追求真理、严谨治学的求实精神，淡泊名利、潜心研究的奉献精神，集智攻关、团结协作的协同精神，甘为人梯、奖掖后学的育人精神。'),
  PoliticalTerm(category: 'dszs', title: '企业家精神', definition: '爱国敬业、遵纪守法、艰苦奋斗，创新发展、专注品质、追求卓越，履行责任、敢于担当、服务社会。'),
  PoliticalTerm(category: 'dszs', title: '探月精神', definition: '追逐梦想、勇于探索、协同攻坚、合作共赢。'),
  PoliticalTerm(category: 'dszs', title: '新时代北斗精神', definition: '自主创新、开放融合、万众一心、追求卓越。'),
  PoliticalTerm(category: 'dszs', title: '丝路精神', definition: '和平合作、开放包容、互学互鉴、互利共赢。'),

  // ═══ 党的二十大报告 (24) ═══
  PoliticalTerm(category: '20d', title: '党的二十大的主题', definition: '高举中国特色社会主义伟大旗帜，全面贯彻新时代中国特色社会主义思想，弘扬伟大建党精神，自信自强、守正创新，踔厉奋发、勇毅前行，为全面建设社会主义现代化国家、全面推进中华民族伟大复兴而团结奋斗。'),
  PoliticalTerm(category: '20d', title: '"三个务必"', definition: '务必不忘初心、牢记使命，务必谦虚谨慎、艰苦奋斗，务必敢于斗争、善于斗争。'),
  PoliticalTerm(category: '20d', title: '三件大事', definition: '一是迎来中国共产党成立一百周年，二是中国特色社会主义进入新时代，三是完成脱贫攻坚、全面建成小康社会的历史任务，实现第一个百年奋斗目标。'),
  PoliticalTerm(category: '20d', title: '习近平新时代中国特色社会主义思想的主要内容', definition: '"十个明确"、"十四个坚持"、"十三个方面成就"。'),
  PoliticalTerm(category: '20d', title: '"六个必须坚持"', definition: '必须坚持人民至上、必须坚持自信自立、必须坚持守正创新、必须坚持问题导向、必须坚持系统观念、必须坚持胸怀天下。'),
  PoliticalTerm(category: '20d', title: '中国共产党的中心任务', definition: '团结带领全国各族人民全面建成社会主义现代化强国、实现第二个百年奋斗目标，以中国式现代化全面推进中华民族伟大复兴。'),
  PoliticalTerm(category: '20d', title: '中国式现代化的中国特色', definition: '中国式现代化是人口规模巨大的现代化、是全体人民共同富裕的现代化、是物质文明和精神文明相协调的现代化、是人与自然和谐共生的现代化、是走和平发展道路的现代化。'),
  PoliticalTerm(category: '20d', title: '中国式现代化的本质要求', definition: '坚持中国共产党领导，坚持中国特色社会主义，实现高质量发展，发展全过程人民民主，丰富人民精神世界，实现全体人民共同富裕，促进人与自然和谐共生，推动构建人类命运共同体，创造人类文明新形态。'),
  PoliticalTerm(category: '20d', title: '全面建成社会主义现代化强国"两步走"战略安排', definition: '从二〇二〇年到二〇三五年基本实现社会主义现代化；从二〇三五年到本世纪中叶把我国建成富强民主文明和谐美丽的社会主义现代化强国。'),
  PoliticalTerm(category: '20d', title: '到二〇三五年我国发展的总体目标', definition: '经济实力、科技实力、综合国力大幅跃升；实现高水平科技自立自强；建成现代化经济体系；基本实现国家治理体系和治理能力现代化；建成教育强国、科技强国、人才强国、文化强国、体育强国、健康中国；人民生活更加幸福美好；广泛形成绿色生产生活方式；国家安全体系和能力全面加强；基本实现国防和军队现代化。'),
  PoliticalTerm(category: '20d', title: '中国式现代化的重大原则', definition: '坚持和加强党的全面领导，坚持中国特色社会主义道路，坚持以人民为中心的发展思想，坚持深化改革开放，坚持发扬斗争精神。'),
  PoliticalTerm(category: '20d', title: '全面建设社会主义现代化国家的首要任务', definition: '高质量发展。'),
  PoliticalTerm(category: '20d', title: '全面建设社会主义现代化国家的基础性、战略性支撑', definition: '教育、科技、人才。'),
  PoliticalTerm(category: '20d', title: '社会主义民主政治的本质属性', definition: '全过程人民民主。'),
  PoliticalTerm(category: '20d', title: '大党独有难题（"六个如何始终"）', definition: '如何始终不忘初心牢记使命、如何始终统一思想统一意志统一行动、如何始终具备强大的执政能力和领导水平、如何始终保持干事创业精神状态、如何始终能够及时发现和解决自身存在的问题、如何始终保持风清气正的政治生态。'),
  PoliticalTerm(category: '20d', title: '"三个区分开来"', definition: '把干部在推进改革中因缺乏经验、先行先试出现的失误和错误，同明知故犯的违纪违法行为区分开来；把上级尚无明确限制的探索性试验中的失误和错误，同上级明令禁止后依然我行我素的违纪违法行为区分开来；把为推动发展的无意过失，同为谋取私利的违纪违法行为区分开来。'),
  PoliticalTerm(category: '20d', title: '"五个必由之路"', definition: '坚持党的全面领导是坚持和发展中国特色社会主义的必由之路；中国特色社会主义是实现中华民族伟大复兴的必由之路；团结奋斗是中国人民创造历史伟业的必由之路；贯彻新发展理念是新时代我国发展壮大的必由之路；全面从严治党是党永葆生机活力、走好新的赶考之路的必由之路。'),
  PoliticalTerm(category: '20d', title: '全过程人民民主', definition: '全过程人民民主是社会主义民主政治的本质属性，是最广泛、最真实、最管用的民主。'),
  PoliticalTerm(category: '20d', title: '全面依法治国', definition: '全面依法治国是国家治理的一场深刻革命，关系党执政兴国，关系人民幸福安康，关系党和国家长治久安。'),
  PoliticalTerm(category: '20d', title: '文化自信自强', definition: '全面建设社会主义现代化国家，必须坚持中国特色社会主义文化发展道路，增强文化自信，建设社会主义文化强国。'),
  PoliticalTerm(category: '20d', title: '国家安全', definition: '国家安全是民族复兴的根基，社会稳定是国家强盛的前提。必须坚定不移贯彻总体国家安全观。'),
  PoliticalTerm(category: '20d', title: '"一国两制"', definition: '"一国两制"是中国特色社会主义的伟大创举，是香港、澳门回归后保持长期繁荣稳定的最佳制度安排，必须长期坚持。'),
  PoliticalTerm(category: '20d', title: '人类命运共同体', definition: '构建人类命运共同体是世界各国人民前途所在。中国始终坚持维护世界和平、促进共同发展的外交政策宗旨，致力于推动构建人类命运共同体。'),
  PoliticalTerm(category: '20d', title: '全面从严治党', definition: '全面建设社会主义现代化国家、全面推进中华民族伟大复兴，关键在党。必须持之以恒推进全面从严治党，以党的自我革命引领社会革命。'),
];
